<script>(function(){const heroSlidesData=@json($heroSlidesData);if(!heroSlidesData.length)return;const originalSetInterval=window.setInterval.bind(window),originalClearInterval=window.clearInterval.bind(window),blockedHeroIntervals=new Set();let blockedId=800000;window.setInterval=function(callback,delay,...args){if(delay===2500&&callback&&callback.name==='goToNextSlide'){const id=++blockedId;blockedHeroIntervals.add(id);return id}return originalSetInterval(callback,delay,...args)};window.clearInterval=function(id){if(blockedHeroIntervals.has(id)){blockedHeroIntervals.delete(id);return}return originalClearInterval(id)};const hero=document.querySelector('.hero'),dotsWrapper=document.getElementById('heroDots'),titleEl=document.querySelector('.hero-title'),subtitleEl=document.querySelector('.hero-subtitle'),prevButton=document.getElementById('prevSlide'),nextButton=document.getElementById('nextSlide');if(!hero||!dotsWrapper)return;document.querySelectorAll('.hero-slide').forEach(slide=>slide.remove());dotsWrapper.innerHTML='';heroSlidesData.forEach((item,index)=>{const slide=document.createElement('div');slide.className=index===0?'hero-slide active':'hero-slide';slide.style.backgroundImage=`url("${item.image}")`;hero.insertBefore(slide,prevButton||hero.firstElementChild);const dot=document.createElement('button');dot.className=index===0?'hero-dot active':'hero-dot';dot.type='button';dot.setAttribute('aria-label',`Slide ${index+1}`);dotsWrapper.appendChild(dot)});const slides=Array.from(document.querySelectorAll('.hero-slide')),dots=Array.from(document.querySelectorAll('.hero-dot'));let currentIndex=0,timerId=null,isAnimating=false;function safeDuration(index){const duration=Number(heroSlidesData[index]?.duration||3000);return Math.min(30000,Math.max(1000,duration))}function updateText(index){const data=heroSlidesData[index]||heroSlidesData[0];if(titleEl)titleEl.innerHTML=String(data.title||'').replace(/\n/g,'<br>');if(subtitleEl)subtitleEl.textContent=data.subtitle||''}function setActiveDot(index){dots.forEach((dot,dotIndex)=>dot.classList.toggle('active',dotIndex===index))}function goToSlide(nextIndex){if(isAnimating||!slides.length)return;const total=slides.length,targetIndex=(nextIndex+total)%total;if(targetIndex===currentIndex)return;isAnimating=true;const currentSlide=slides[currentIndex],nextSlide=slides[targetIndex];nextSlide.classList.remove('slide-out-left');nextSlide.classList.add('active');currentSlide.classList.add('slide-out-left');currentSlide.classList.remove('active');currentIndex=targetIndex;updateText(currentIndex);setActiveDot(currentIndex);setTimeout(()=>{currentSlide.classList.remove('slide-out-left');isAnimating=false},800)}function scheduleNext(){clearTimeout(timerId);timerId=setTimeout(()=>{goToSlide(currentIndex+1);scheduleNext()},safeDuration(currentIndex))}function resetAutoSlide(){clearTimeout(timerId);scheduleNext()}prevButton?.addEventListener('click',function(event){event.preventDefault();event.stopImmediatePropagation();goToSlide(currentIndex-1);resetAutoSlide()},true);nextButton?.addEventListener('click',function(event){event.preventDefault();event.stopImmediatePropagation();goToSlide(currentIndex+1);resetAutoSlide()},true);dots.forEach((dot,index)=>{dot.addEventListener('click',function(event){event.preventDefault();event.stopImmediatePropagation();goToSlide(index);resetAutoSlide()},true)});updateText(0);scheduleNext()})();</script>
