<script>
(function(){
const API_ORIGIN='https://panel-web.unw.ac.id';const API={news:API_ORIGIN+'/api/news',category:API_ORIGIN+'/api/category'};
function esc(value){return String(value??'').replace(/[&<>'"]/g,function(char){return {'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#039;','"':'&quot;'}[char]})}
function stripHtml(value){return String(value??'').replace(/<[^>]*>/g,'').replace(/\s+/g,' ').trim()}function toArray(payload){if(Array.isArray(payload))return payload;if(Array.isArray(payload?.data))return payload.data;if(Array.isArray(payload?.data?.data))return payload.data.data;return[]}function absUrl(url){if(!url)return'';const value=String(url);if(/^https?:\/\//i.test(value))return value;if(value.startsWith('//'))return 'https:'+value;if(value.startsWith('/'))return API_ORIGIN+value;return API_ORIGIN+'/'+value.replace(/^\/+/, '')}function formatDate(value){if(!value)return'';const date=new Date(value);if(Number.isNaN(date.getTime()))return String(value);return date.toLocaleDateString('id-ID',{day:'2-digit',month:'long',year:'numeric'})}async function getJson(url){const response=await fetch(url,{headers:{Accept:'application/json'}});if(!response.ok)throw new Error('API gagal dimuat');return response.json()}function readMeta(payload){const meta=payload?.meta||payload?.pagination||{};return{current:Number(meta.current_page||1),last:Number(meta.last_page||1),total:Number(meta.total||0),perPage:Number(meta.per_page||4)}}function normalizeCategory(item){return{id:String(item?.id??''),slug:String(item?.slug??''),name:String(item?.name??'').trim()}}function normalizeNews(item){const category=item?.category||{};return{id:String(item?.id??item?.slug??Math.random()),title:String(item?.title??'Tanpa Judul'),slug:String(item?.slug??''),image:String(item?.image_thumbnail||item?.image||''),excerpt:String(item?.excerpt??''),date:String(item?.publishedAt||item?.published_at||item?.createdAt||item?.created_at||''),categoryId:String(category?.id??item?.category_id??''),categorySlug:String(category?.slug??''),categoryName:String(category?.name??'Artikel').trim()}}function newsDetailUrl(news){return news.slug?'/berita/'+encodeURIComponent(news.slug):'#'}function buildNewsApiUrl(page,category){const params=new URLSearchParams();params.set('paginate','4');params.set('page',String(page));if(category&&category.id!=='all'){params.set('category_id',category.id);params.set('category',category.slug||category.id)}return API.news+'?'+params.toString()}
function renderFilters(section,state){const target=section.querySelector('#apiCategoryFilter');if(!target)return;let html='<button class="news-filter-btn active" type="button" data-id="all" data-slug="all">Semua</button>';html+=state.categories.map(function(category){return '<button class="news-filter-btn" type="button" data-id="'+esc(category.id)+'" data-slug="'+esc(category.slug)+'">'+esc(category.name)+'</button>'}).join('');target.innerHTML=html;target.querySelectorAll('.news-filter-btn').forEach(function(button){button.addEventListener('click',function(){target.querySelectorAll('.news-filter-btn').forEach(function(item){item.classList.remove('active')});button.classList.add('active');state.category={id:button.dataset.id,slug:button.dataset.slug};state.page=1;loadNews(section,state)})})}
function renderNews(section,items){const target=section.querySelector('#apiNewsList');if(!target)return;if(!items.length){target.innerHTML='<div class="news-state">Belum ada berita/artikel pada kategori ini.</div>';return}target.innerHTML=items.map(function(news){const image=news.image?'<img src="'+esc(absUrl(news.image))+'" alt="'+esc(news.title)+'" loading="lazy">':'<svg viewBox="0 0 24 24"><path d="M21 19V5c0-1.1-.9-2-2-2H5c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h14c1.1 0 2-.9 2-2ZM8.5 11.5l2.5 3.01L14.5 10l4.5 6H5l3.5-4.5Z"/></svg>';const excerpt=stripHtml(news.excerpt);return '<article class="news-item"><a class="news-item-link" href="'+esc(newsDetailUrl(news))+'"><div class="news-thumb">'+image+'</div><div class="news-content"><div class="news-category"><svg viewBox="0 0 24 24"><path d="M20.59 13.41 12 22l-8.59-8.59A2 2 0 0 1 3 12V4a1 1 0 0 1 1-1h8a2 2 0 0 1 1.41.59L22 12.17l-1.41 1.24ZM7.5 8A1.5 1.5 0 1 0 7.5 5 1.5 1.5 0 0 0 7.5 8Z"/></svg>'+esc(news.categoryName)+'</div><h3 class="news-title">'+esc(news.title)+'</h3>'+(excerpt?'<p class="news-excerpt">'+esc(excerpt.slice(0,155))+'</p>':'')+'<div class="news-date"><svg viewBox="0 0 24 24"><path d="M7 2h2v2h6V2h2v2h3a1 1 0 0 1 1 1v16a1 1 0 0 1-1 1H4a1 1 0 0 1-1-1V5a1 1 0 0 1 1-1h3V2Zm12 8H5v10h14V10ZM5 8h14V6H5v2Zm2 4h3v3H7v-3Zm5 0h3v3h-3v-3Z"/></svg>'+esc(formatDate(news.date))+'</div></div></a></article>'}).join('')}
function renderPagination(section,state){const target=section.querySelector('#apiNewsPagination');if(!target)return;const last=Math.max(1,Number(state.lastPage||1));const current=Math.min(Math.max(1,Number(state.page||1)),last);let start=Math.max(1,current-1);let end=Math.min(last,start+3);if(end-start<3)start=Math.max(1,end-3);let html='<button class="page-btn" type="button" data-page="'+(current-1)+'" '+(current<=1?'disabled':'')+'>‹</button>';for(let page=start;page<=end;page++){html+='<button class="page-number '+(page===current?'active':'')+'" type="button" data-page="'+page+'">'+page+'</button>'}if(end<last){html+='<span>...</span><button class="page-number" type="button" data-page="'+last+'">'+last+'</button>'}html+='<button class="page-btn dark" type="button" data-page="'+(current+1)+'" '+(current>=last?'disabled':'')+'>›</button>';target.innerHTML=html;target.querySelectorAll('button[data-page]').forEach(function(button){button.addEventListener('click',function(){const page=Number(button.dataset.page);if(page>=1&&page<=last&&page!==current){state.page=page;loadNews(section,state)}})})}
async function loadNews(section,state){const target=section.querySelector('#apiNewsList');if(target)target.innerHTML='<div class="news-state">Memuat berita dari API...</div>';try{const category=state.category?.id==='all'?null:state.category;const payload=await getJson(buildNewsApiUrl(state.page,category));let items=toArray(payload).map(normalizeNews);const meta=readMeta(payload);if(category){const before=items.length;items=items.filter(function(news){return String(news.categoryId)===String(category.id)||String(news.categorySlug)===String(category.slug)});if(!items.length&&before){const largePayload=await getJson(API.news+'?paginate=100&page=1');items=toArray(largePayload).map(normalizeNews).filter(function(news){return String(news.categoryId)===String(category.id)||String(news.categorySlug)===String(category.slug)});state.lastPage=Math.max(1,Math.ceil(items.length/4));items=items.slice((state.page-1)*4,state.page*4)}else{state.lastPage=meta.last||1}}else{state.lastPage=meta.last||1}state.page=meta.current&&(!category||items.length)?meta.current:state.page;renderNews(section,items);renderPagination(section,state)}catch(error){if(target)target.innerHTML='<div class="news-state">Berita belum dapat dimuat dari API. Periksa koneksi internet atau izin CORS API.</div>'}}
async function initInfoSectionApi(){const section=document.getElementById('layanan-mahasiswa');if(!section)return;const newsArea=section.querySelector('.news-area');if(!newsArea)return;newsArea.innerHTML='<div class="section-header"><h2 class="section-title">Berita Terkini & Agenda</h2><div class="pagination" id="apiNewsPagination"></div></div><div class="news-filter-bar" id="apiCategoryFilter"></div><div class="news-list" id="apiNewsList"><div class="news-state">Memuat berita...</div></div>';const state={page:1,lastPage:1,category:{id:'all',slug:'all'},categories:[]};try{const categoryPayload=await getJson(API.category);state.categories=toArray(categoryPayload).map(normalizeCategory).filter(function(category){return category.id&&category.name});renderFilters(section,state)}catch(error){renderFilters(section,state)}loadNews(section,state)}
function isUsableRouteLink(link){const rawHref=link.getAttribute('href')||'',trimmedHref=rawHref.trim();if(!trimmedHref||trimmedHref==='#'||trimmedHref.startsWith('#')||trimmedHref.toLowerCase().startsWith('javascript:'))return false;try{const url=new URL(link.href,window.location.origin);return url.origin===window.location.origin}catch(error){return false}}function normalizePath(value){try{const url=new URL(value,window.location.origin);return url.pathname.replace(/\/+$/,'')||'/'}catch(error){return String(value||'').replace(/\/+$/,'')||'/'}}function activateHeaderByCurrentPage(){const currentPath=normalizePath(window.location.pathname),navMenu=document.getElementById('navMenu');if(!navMenu)return;const navItems=navMenu.querySelectorAll('.nav-item'),navLinks=navMenu.querySelectorAll('.nav-link'),dropdownLinks=navMenu.querySelectorAll('.dropdown a'),homeNavItem=document.getElementById('homeNavItem');navItems.forEach(item=>item.classList.remove('route-active'));navLinks.forEach(link=>link.classList.remove('nav-route-active','nav-click-active'));dropdownLinks.forEach(link=>link.classList.remove('dropdown-route-active'));let activeTopLink=null,activeDropdownLink=null;dropdownLinks.forEach(link=>{if(!isUsableRouteLink(link))return;const linkPath=normalizePath(link.href);if(linkPath===currentPath)activeDropdownLink=link});if(activeDropdownLink){const parentItem=activeDropdownLink.closest('.nav-item'),parentLink=parentItem?.querySelector(':scope > .nav-link');activeDropdownLink.classList.add('dropdown-route-active');parentItem?.classList.add('route-active');parentLink?.classList.add('nav-route-active');homeNavItem?.classList.add('hide-indicator');return}navLinks.forEach(link=>{if(!isUsableRouteLink(link))return;const linkPath=normalizePath(link.href);if(linkPath===currentPath)activeTopLink=link});if(activeTopLink){const parentItem=activeTopLink.closest('.nav-item');parentItem?.classList.add('route-active');activeTopLink.classList.add('nav-route-active');if(parentItem?.id==='homeNavItem')homeNavItem?.classList.remove('hide-indicator');else homeNavItem?.classList.add('hide-indicator');return}if(currentPath.startsWith('/akademik')){const akademikItem=Array.from(navItems).find(item=>item.textContent.trim().toLowerCase().startsWith('akademik')),akademikLink=akademikItem?.querySelector(':scope > .nav-link');akademikItem?.classList.add('route-active');akademikLink?.classList.add('nav-route-active');homeNavItem?.classList.add('hide-indicator');return}if(currentPath.startsWith('/profil')||currentPath==='/visi-misi'||currentPath==='/tentang-pascasarjana'){const profilItem=Array.from(navItems).find(item=>item.textContent.trim().toLowerCase().startsWith('profil')),profilLink=profilItem?.querySelector(':scope > .nav-link');profilItem?.classList.add('route-active');profilLink?.classList.add('nav-route-active');homeNavItem?.classList.add('hide-indicator');return}if(currentPath==='/'){const homeLink=homeNavItem?.querySelector('.nav-link');homeNavItem?.classList.add('route-active');homeLink?.classList.add('nav-route-active');homeNavItem?.classList.remove('hide-indicator')}}function bindProgramDetailLinks(){const programCards=document.querySelectorAll('.program-section .program-card'),programDetailRoutes=["{{ route('akademik.show', 'magister-hukum') }}","{{ route('akademik.show', 'magister-manajemen-pendidikan') }}","{{ route('akademik.show', 'magister-kesehatan-masyarakat') }}","{{ route('akademik.show', 'magister-keperawatan') }}"];programCards.forEach(function(card,index){const url=programDetailRoutes[index];if(!url)return;card.setAttribute('href',url);card.setAttribute('aria-label','Lihat detail program studi');const detailText=card.querySelector('.program-detail');if(detailText){detailText.setAttribute('role','link');detailText.setAttribute('tabindex','0');detailText.dataset.href=url}})}document.addEventListener('click',function(event){const detailText=event.target.closest('.program-section .program-detail');if(!detailText||!detailText.dataset.href)return;event.preventDefault();event.stopPropagation();window.location.href=detailText.dataset.href},true);document.addEventListener('keydown',function(event){const detailText=event.target.closest('.program-section .program-detail');if(!detailText||!detailText.dataset.href)return;if(event.key==='Enter'||event.key===' '){event.preventDefault();window.location.href=detailText.dataset.href}},true);if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',function(){bindProgramDetailLinks();activateHeaderByCurrentPage();initInfoSectionApi()});else{bindProgramDetailLinks();activateHeaderByCurrentPage();initInfoSectionApi()}
})();
</script>